        let raw = r#"{"groups": [
            {"files": ["a.rs"], "message": "feat: one"},
            {"files": ["b.rs", "surprise.rs"], "message": "feat: two"}
        ]}"#;
        let expected = vec!["a.rs".to_string(), "b.rs".to_string()];
        let result = parse_split_response(raw, &expected);
